export async function createProxy(main, rev={}){
  const b=new Worker(
    process.env.PNODE_BOOTLOADER_URL||
    process.env.WEBCARTRIDGE_MAIN,{
      type:"module"
    });
  const w=rpc.proxy.client(b,"boot");
  const fstab=getDeviceManager().
    readFstab("/fstab.json",[]);
  const id=Math.random()+"";
  await w.boot({
    fstab,
    id,
    main:main.path()
  });
  const m=rpc.proxy.client(b,"default");
  const revserv=rpc.proxy.server(b, id, [], rev);

  return m;
}